def pourWater(heights, V, K):
    for _ in range(V):
        best = K
        for d in [-1, 1]:
            i = K + d; cur = K
            while 0 <= i < len(heights) and heights[i] <= heights[cur]:
                if heights[i] < heights[cur]: cur = i
                i += d
            if cur != K: best = cur; break
        heights[best] += 1
    return heights

